import React, { useEffect, useState } from "react";
import axios from "axios";
import { Bar, Pie } from "react-chartjs-2";
import './AdminDashboard.css';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, Tooltip, Legend);

const AdminDashboard = () => {
  const [predictions, setPredictions] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get("http://localhost:5000/admin/dashboard");
        setPredictions(res.data.predictions || []);
      } catch (err) {
        console.error("Error fetching data:", err);
      }
    };
    fetchData();
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  const totalUsers = predictions.length;
  const salaries = predictions.map(p => p.salary).filter(s => s != null);
  const avgSalary = salaries.length ? (salaries.reduce((a, b) => a + b, 0) / salaries.length) : 0;
  const highestSalary = salaries.length ? Math.max(...salaries) : 0;
  const lowestSalary = salaries.length ? Math.min(...salaries) : 0;

  const barData = {
    labels: ["<40k", "40-60k", "60-80k", "80-100k", ">100k"],
    datasets: [{
      label: "Number of Predictions",
      data: [
        predictions.filter(p => p.salary < 40000).length,
        predictions.filter(p => p.salary >= 40000 && p.salary < 60000).length,
        predictions.filter(p => p.salary >= 60000 && p.salary < 80000).length,
        predictions.filter(p => p.salary >= 80000 && p.salary < 100000).length,
        predictions.filter(p => p.salary >= 100000).length,
      ],
      backgroundColor: "#22A6B3",
      borderRadius: 4,
    }]
  };

  const pieData = {
    labels: ["Experienced", "Entry-Level", "Intermediate", "Post-Graduate"],
    datasets: [{
      data: [
        predictions.filter(p => p.experience === "Experienced").length || 1,
        predictions.filter(p => p.experience === "Entry").length || 1,
        predictions.filter(p => p.experience === "Intermediate").length || 1,
        predictions.filter(p => p.experience === "Post-Graduate").length || 1
      ],
      backgroundColor: ["#4834D4", "#F0932B", "#6AB04C", "#EB4D4B"]
    }]
  };

  return (
    <div className="dashboard-wrapper">
      <aside className="app-sidebar">
        <div className="profile-section">
          <div className="avatar-circle">👤</div>
          <h3>Admin</h3>
        </div>
        <ul className="nav-menu">
          <li className="active">Dashboard</li>
          <li>Manage Users</li>
          <li>Reports</li>
          <li>Settings</li>
        </ul>
        <button className="logout-action" onClick={handleLogout}>Logout</button>
      </aside>

      <main className="dashboard-main">
        <header className="top-nav">
          <h2>Admin Dashboard</h2>
          <div className="top-nav-right">🔔 👤</div>
        </header>

        <div className="content-scroll">
          <section className="stats-grid">
            <div className="stat-card blue-grad">
              <p>Avg. Salary</p>
              <h3>₹{avgSalary.toLocaleString()}</h3>
            </div>
            <div className="stat-card purple-grad">
              <p>Highest Salary</p>
              <h3>₹{highestSalary.toLocaleString()}</h3>
            </div>
            <div className="stat-card orange-grad">
              <p>Lowest Salary</p>
              <h3>₹{lowestSalary.toLocaleString()}</h3>
            </div>
            <div className="stat-card green-grad">
              <p>Total Users</p>
              <h3>{totalUsers}</h3>
            </div>
          </section>

          <section className="visuals-row">
            <div className="visual-box">
              <h4>Salary Distribution</h4>
              <div className="chart-container">
                <Bar data={barData} options={{ maintainAspectRatio: false }} />
              </div>
            </div>
            <div className="visual-box">
              <h4>User Demographics</h4>
              <div className="chart-container">
                <Pie data={pieData} options={{ maintainAspectRatio: false }} />
              </div>
            </div>
          </section>

          <section className="recent-table">
            <h4>Recent Predictions</h4>
            <table>
              <thead>
                <tr>
                  <th>Email</th>
                  <th>Job Role</th>
                  <th>Location</th>
                  <th>Predicted Salary</th>
                </tr>
              </thead>
              <tbody>
                {predictions.slice(-5).reverse().map((p, i) => (
                  <tr key={i}>
                    <td>{p.email}</td>
                    <td>{p.role}</td>
                    <td>{p.location}</td>
                    <td className="bold-text">₹{p.salary?.toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </section>
        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
